namespace UniversityCourseCatalog.Data;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public string Code { get; set; } = "";
    public string Description { get; set; } = "";
}

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public string Title { get; set; } = "";
    public string Bio { get; set; } = "";
    public string Email { get; set; } = "";
}

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = "";
    public string Title { get; set; } = "";
    public string Description { get; set; } = "";
    public int Credits { get; set; }
    public string Schedule { get; set; } = "";
    public int DepartmentId { get; set; }
    public Department Department { get; set; } = null!;
    public Instructor Instructor { get; set; } = null!;
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = "";
    public string StudentId { get; set; } = "";
    public int CourseId { get; set; }
}

namespace UniversityCourseCatalog.Data;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." },
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Sarah Chen", Title = "Professor", Bio = "Specializes in algorithms and machine learning with 15 years of teaching experience. Published over 50 research papers.", Email = "s.chen@university.edu" },
            new() { Id = 2, Name = "Dr. James Miller", Title = "Associate Professor", Bio = "Expert in abstract algebra and number theory. Recipient of the Distinguished Teaching Award.", Email = "j.miller@university.edu" },
            new() { Id = 3, Name = "Dr. Emily Watson", Title = "Professor", Bio = "Researcher in quantum mechanics and particle physics. Former visiting scholar at CERN.", Email = "e.watson@university.edu" },
            new() { Id = 4, Name = "Dr. Michael Brooks", Title = "Assistant Professor", Bio = "Published novelist and literary critic focusing on contemporary American fiction.", Email = "m.brooks@university.edu" },
            new() { Id = 5, Name = "Dr. Lisa Park", Title = "Professor", Bio = "Historian of early modern Europe with expertise in the Renaissance period.", Email = "l.park@university.edu" },
            new() { Id = 6, Name = "Dr. Robert Taylor", Title = "Associate Professor", Bio = "Focuses on data structures, distributed systems, and software engineering.", Email = "r.taylor@university.edu" },
        };

        _departments.ForEach(d => { }); // ensure initialized

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Covers variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, Instructor = _instructors[0], Department = _departments[0], IsFeatured = true },
            new() { Id = 2, Code = "CS 301", Title = "Data Structures & Algorithms", Description = "Advanced study of data structures including trees, graphs, and hash tables. Algorithm design and complexity analysis.", Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM", DepartmentId = 1, Instructor = _instructors[5], Department = _departments[0], IsFeatured = true },
            new() { Id = 3, Code = "CS 450", Title = "Machine Learning", Description = "Introduction to statistical learning, neural networks, and practical applications of AI in industry.", Credits = 3, Schedule = "Mon/Wed 2:00–3:30 PM", DepartmentId = 1, Instructor = _instructors[0], Department = _departments[0], IsFeatured = true },
            new() { Id = 4, Code = "MATH 201", Title = "Linear Algebra", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to computer science and engineering.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = 2, Instructor = _instructors[1], Department = _departments[1] },
            new() { Id = 5, Code = "MATH 301", Title = "Abstract Algebra", Description = "Groups, rings, fields, and their applications. Proof-based course for math majors.", Credits = 3, Schedule = "Tue/Thu 1:00–2:30 PM", DepartmentId = 2, Instructor = _instructors[1], Department = _departments[1] },
            new() { Id = 6, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based introductory course with lab component.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM + Thu Lab 2:00–4:50 PM", DepartmentId = 3, Instructor = _instructors[2], Department = _departments[2], IsFeatured = true },
            new() { Id = 7, Code = "PHYS 320", Title = "Quantum Mechanics", Description = "Wave functions, Schrödinger equation, quantum states, and measurement theory.", Credits = 3, Schedule = "Tue/Thu 9:00–10:30 AM", DepartmentId = 3, Instructor = _instructors[2], Department = _departments[2] },
            new() { Id = 8, Code = "ENG 102", Title = "College Writing", Description = "Develop academic writing skills through essays, research papers, and peer review workshops.", Credits = 3, Schedule = "Mon/Wed 10:00–11:30 AM", DepartmentId = 4, Instructor = _instructors[3], Department = _departments[3] },
            new() { Id = 9, Code = "ENG 350", Title = "American Literature", Description = "Survey of American literature from the colonial period to the present. Critical analysis and discussion.", Credits = 3, Schedule = "Tue/Thu 3:00–4:30 PM", DepartmentId = 4, Instructor = _instructors[3], Department = _departments[3] },
            new() { Id = 10, Code = "HIST 201", Title = "Western Civilization", Description = "Political, social, and cultural history of Europe from antiquity through the modern era.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", DepartmentId = 5, Instructor = _instructors[4], Department = _departments[4] },
            new() { Id = 11, Code = "HIST 340", Title = "The Renaissance", Description = "Art, politics, and intellectual life in 14th–16th century Europe.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:30 PM", DepartmentId = 5, Instructor = _instructors[4], Department = _departments[4] },
            new() { Id = 12, Code = "CS 201", Title = "Object-Oriented Programming", Description = "Design principles, inheritance, polymorphism, and software patterns using C# and Java.", Credits = 3, Schedule = "Tue/Thu 2:00–3:30 PM", DepartmentId = 1, Instructor = _instructors[5], Department = _departments[0] },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real app this would persist to a database
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && request.CourseId > 0
            && _courses.Any(c => c.Id == request.CourseId);
    }
}

