arguments.file_text:
@page "/"
@inject UniversityCourseCatalog.Data.CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<h1>University Course Catalog</h1>
<p class="lead">Welcome to the course catalog. Browse departments, explore courses, and submit enrollment requests.</p>

<h2 class="mt-4">Featured Courses</h2>
<div class="row">
    @foreach (var course in featuredCourses)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.Code</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                    <p class="card-text">@course.Credits credits &middot; @course.Department.Name</p>
                    <a href="courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mt-5">Departments</h2>
<div class="row">
    @foreach (var dept in departments)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name</h5>
                    <p class="card-text text-muted">@dept.Description</p>
                    <a href="courses?departmentId=@dept.Id" class="btn btn-outline-secondary btn-sm">Browse Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<UniversityCourseCatalog.Data.Course> featuredCourses = new();
    private List<UniversityCourseCatalog.Data.Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }
}

@page "/courses"
@inject UniversityCourseCatalog.Data.CatalogService CatalogService

<PageTitle>Courses - University Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" action="courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search courses..." />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Schedule</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@course.Department.Name</td>
                    <td>@course.Credits</td>
                    <td>@course.Schedule</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<UniversityCourseCatalog.Data.Course> courses = new();
    private List<UniversityCourseCatalog.Data.Department> departments = new();

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        courses = CatalogService.GetCourses(Search, DepartmentId);
    }
}

@page "/enroll"
@inject UniversityCourseCatalog.Data.CatalogService CatalogService

<PageTitle>Enrollment Request - University Course Catalog</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit your enrollment request below. You will receive a confirmation email once processed.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Your enrollment request for <strong>@selectedCourseName</strong> has been received. You will be contacted at your university email.</p>
        <a href="courses" class="btn btn-primary mt-2">Browse More Courses</a>
    </div>
}
else
{
    if (validationError is not null)
    {
        <div class="alert alert-danger">@validationError</div>
    }

    <form method="post" action="enroll" @formname="enrollment">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <input type="text" id="studentName" name="@nameof(Model.StudentName)" value="@Model.StudentName" class="form-control" required />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" id="studentId" name="@nameof(Model.StudentId)" value="@Model.StudentId" class="form-control" required placeholder="e.g. S12345678" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select id="courseId" name="@nameof(Model.CourseId)" class="form-select" required>
                <option value="">-- Select a course --</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.Code - @course.Title (@course.Credits cr)</option>
                }
            </select>
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
    </form>
}

@code {
    [SupplyParameterFromForm] private UniversityCourseCatalog.Data.EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<UniversityCourseCatalog.Data.Course> courses = new();
    private bool submitted;
    private string? validationError;
    private string? selectedCourseName;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }

        // Handle form POST
        if (!string.IsNullOrWhiteSpace(Model.StudentName) && Model.CourseId > 0)
        {
            if (string.IsNullOrWhiteSpace(Model.StudentId))
            {
                validationError = "Please provide your Student ID.";
                return;
            }

            var success = CatalogService.SubmitEnrollmentRequest(Model);
            if (success)
            {
                var course = CatalogService.GetCourse(Model.CourseId);
                selectedCourseName = course is not null ? $"{course.Code} - {course.Title}" : "the selected course";
                submitted = true;
            }
            else
            {
                validationError = "Unable to process your request. Please verify all fields and try again.";
            }
        }
    }
}

